message.content:
{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式発足を承認し、本日をもって第1回全体会議を開催して進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "移行方式は段階移行（B案）とし、拠点を複数に分けて順次切り替える進め方を決定した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリースの目標期限を9月末から10月15日に引き下げることを決めた。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信については、サクラ商事さんの共同利用（第3案）を採用し、回答書を来週の金曜までに送付する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "移行リハーサルの手順書作成担当を白鳥千夏から沼田賢一に変更した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "障害対応の一次受け窓口をQAチーム（白鳥）に設定し、既知不具合からの回避策提供などを行うことを決めた。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "新システムでのロール定義は既存を流用するとし、業務実態との整合性向上については稼働後の運用改善として別途検討することにした。",
      "decided_by": "芦田 巧"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "API仕様書のドラフトを作成する",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A2",
      "task": "検証環境のサーバ調達依頼を出す",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "現場ヒアリングの対象部署リストを作成し提出する",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A4",
      "task": "稟議（ベンダー見積）の起票を行う",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A5",
      "task": "サクラ商事さんへの共同利用の回答書を作成・送付する",
      "assignee": "桐生 遥",
      "due": "2026-05-23"
    },
    {
      "id": "A6",
      "task": "外部ライセンス費用の見積もりを再取得し（年契約条件も含め）共有する",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A7",
      "task": "移行テスト計画を立てて出せる（方式が決まらなくても観点と回数枠は先に置く）",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A8",
      "task": "負荷テスト計画（シナリオ含め）を作成する",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A9",
      "task": "移行リハーサルの手順書（切り戻しの手順込み）を作成する",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A10",
      "task": "既存テストケースの棚卸し（生きてるもの、捨てるもの、修正を要するものの分類）を行う",
      "assignee": "白鳥 千夏",
      "due": "2026-05-31"
    },
    {
      "id": "A11",
      "task": "全拠点向けの現場説明会（移行や新システムに関する）の日程を案出して周知する",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    },
    {
      "id": "A12",
      "task": "拠点ごとの移行グループ分けの案を整理して共有する",
      "assignee": "芦田 巧",
      "due": "未定"
    }
  ],
